<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        .flags    </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NL_CFG_F_NONROOT_RECV,</span></span>
